solution_code:
#include <iostream>

void swapPtrs(int** pp1, int** pp2) {
    int* tmp { *pp1 };
    *pp1 = *pp2;
    *pp2 = tmp;
}

int main() {
    int a {}, b {};
    std::cin >> a >> b;

    int* p1 { &a };
    int* p2 { &b };

    swapPtrs(&p1, &p2);

    std::cout << "First: "  << *p1 << '\n';
    std::cout << "Second: " << *p2 << '\n';
    return 0;
}

