solution_code:
#include <iostream>

// Makes the caller's pointer point at the larger of *pa or *pb
void pointToLarger(int** result, int* pa, int* pb) {
    if (*pb > *pa)
        *result = pb;
    else
        *result = pa;
}

int main() {
    int a {}, b {};
    std::cin >> a >> b;

    int* winner { &a };   // start pointing at a
    pointToLarger(&winner, &a, &b);
    std::cout << "Larger: " << *winner << '\n';
    return 0;
}
